const HR=require("./hr.js");describe("HR.js",()=>{test("highlight backgroundColor should match",async()=>{var t="lorem ipsum dolor sit amet.",t=(document.body.innerHTML=`<p id="test-1">${t}</p>`,new HR("#test-1",{highlight:t}).hr(),document.getElementById("test-1"));expect(t.children[0].style.backgroundColor).toBe("rgb(255, 222, 112)")}),test("replaceWith & backgroundColor values should match",async()=>{var t="black",e="white",t=(document.body.innerHTML=`<p id="test-2">${t}</p>`,new HR("#test-2",{highlight:t,replaceWith:e,backgroundColor:"rgb(180, 255, 235)"}).hr(),document.getElementById("test-2"));expect(t.textContent).toBe(e),expect(t.children[0].style.backgroundColor).toBe("rgb(180, 255, 235)")}),test("array of items replace should match",async()=>{var t="cat bird",e="dog unicorn";document.body.innerHTML=`<p id="test-3">${t}</p>`,new HR("#test-3",{highlight:t.split(" "),replaceWith:e.split(" "),backgroundColor:"rgb(0, 255, 235)"}).hr();const o=document.getElementById("test-3");expect(o.textContent.trim()).toBe(e)})});